// 生成需要检查的URL列表
const config = JSON.parse($json.backlinkConfig);

// 添加已知外链
const checkList = config.knownBacklinks.map(bl => ({
  url: bl.url,
  name: bl.name,
  priority: bl.priority,
  type: bl.type,
  checkType: 'known'
}));

// 添加搜索查询URL来发现新的外链机会
for (const keyword of config.targetKeywords) {
  checkList.push({
    url: `https://www.baidu.com/s?wd=${encodeURIComponent(keyword + ' site:dajilin.net')}`,
    name: `关键词"${keyword}"外链检查`,
    priority: 'medium',
    type: 'keyword_search',
    checkType: 'discover'
  });
}

return checkList;

// 分析外链有效性
const pageContent = $input.first().json.response || '';
const urlInfo = $('生成检查列表').first().json;
const siteUrl = 'dajilin.net';

let result = {
  url: urlInfo.url,
  name: urlInfo.name,
  priority: urlInfo.priority,
  type: urlInfo.type,
  checkType: urlInfo.checkType,
  isAlive: false,
  hasOurLink: false,
  pageTitle: '',
  linkContext: '',
  checkedAt: new Date().toISOString()
};

// 检查页面是否可访问
if (pageContent && pageContent.length > 100) {
  result.isAlive = true;

  // 检查是否包含我们的链接
  if (pageContent.includes(siteUrl) || pageContent.includes('dajilin')) {
    result.hasOurLink = true;

    // 提取链接上下文
    const linkMatch = pageContent.match(new RegExp(`.{50}dajilin[^<]{0,100}`));
    if (linkMatch) {
      result.linkContext = linkMatch[0].substring(0, 150);
    }

    // 提取页面标题
    const titleMatch = pageContent.match(/<title[^>]*>([^<]+)<\/title>/i);
    if (titleMatch) {
      result.pageTitle = titleMatch[1].trim();
    }
  }
}

return [result];

// 聚合所有检查结果
const results = $input.all();
const config = JSON.parse($json.backlinkConfig);

const summary = {
  reportTime: new Date().toLocaleString('zh-CN'),
  siteUrl: config.siteUrl,
  totalChecked: results.length,
  aliveCount: 0,
  deadCount: 0,
  hasOurLinkCount: 0,
  noLinkCount: 0,
  byPriority: { high: [], medium: [], low: [] },
  byType: {},
  newOpportunities: [],
  recommendations: []
};

for (const r of results) {
  if (r.isAlive) {
    summary.aliveCount++;

    if (r.hasOurLink) {
      summary.hasOurLinkCount++;

      // 按优先级分类
      if (r.priority) {
        summary.byPriority[r.priority].push(r);
      }

      // 按类型分类
      if (!summary.byType[r.type]) {
        summary.byType[r.type] = [];
      }
      summary.byType[r.type].push(r);
    } else if (r.checkType === 'known') {
      summary.noLinkCount++;
    }
  } else {
    summary.deadCount++;
    summary.recommendations.push(`⚠️ 外链失效: ${r.name} (${r.url})`);
  }
}

// 生成新机会
if (summary.noLinkCount > 0) {
  summary.recommendations.push(`📋 ${summary.noLinkCount}个已知平台尚未建立外链，需手动联系`);
}

// 总体建议
if (summary.hasOurLinkCount === 0 && summary.aliveCount > 0) {
  summary.recommendations.push('❌ 没有任何外链被检测到，建议：1) 确认外链URL正确 2) 联系平台添加外链');
} else if (summary.hasOurLinkCount > 0) {
  summary.recommendations.push(`✅ 已建立${summary.hasOurLinkCount}个有效外链`);
}

summary.recommendations.push('📈 建议持续在马蜂窝、知乎、百度百科等平台发布内容并附带外链');

return [summary];

// 生成外链检查报告
const summary = $input.first().json;

let html = `<h2>外部GEO外链监控报告</h2>
<p><strong>检查时间:</strong> ${summary.reportTime}</p>
<p><strong>监测网站:</strong> ${summary.siteUrl}</p>

<h3>概览</h3>
<ul>
<li>总检查数: ${summary.totalChecked}</li>
<li>有效页面: ${summary.aliveCount} ✅</li>
<li>失效页面: ${summary.deadCount} ❌</li>
<li>包含我们外链: ${summary.hasOurLinkCount} ✅</li>
<li>尚无外链: ${summary.noLinkCount} ⚠️</li>
</ul>

<h3>高优先级外链状态</h3>`;

if (summary.byPriority.high && summary.byPriority.high.length > 0) {
  html += '<table border="1"><tr><th>平台</th><th>状态</th><th>标题</th></tr>';
  for (const link of summary.byPriority.high) {
    html += `<tr><td>${link.name}</td><td>${link.hasOurLink ? '✅ 有外链' : '⚠️ 无外链'}</td><td>${link.pageTitle || '-'}</td></tr>`;
  }
  html += '</table>';
} else {
  html += '<p>暂无高优先级外链</p>';
}

html += `<h3>优化建议</h3>
<ol>`;
for (const rec of summary.recommendations) {
  html += `<li>${rec}</li>`;
}
html += '</ol>';

html += `<h3>外链建设工作</h3>
<ol>
<li><strong>政府合作:</strong> 联系吉林省文旅厅、长春市文旅局获取外链</li>
<li><strong>媒体合作:</strong> 与吉林日报、中国旅游报等建立内容合作</li>
<li><strong>平台入驻:</strong> 在马蜂窝、携程、飞猪开设官方账号并发布内容</li>
<li><strong>百科建设:</strong> 在百度百科、搜狗百科完善吉林景点词条</li>
</ol>

<p><small>由n8n自动生成 | ${new Date().toISOString()}</small></p>`;

return [{ html, summary }];
